// Build a Map once at module load for O(1) lookups — replaces O(n) STATIC_LABELS.find()
const STATIC_LABELS_MAP = new Map(
    STATIC_LABELS.map((l) => [l.key, l])
);

export const LanguageProvider = ({ children }: { children: ReactNode }) => {
    const [languages, setLanguages] = useState<Language[]>([]);
    const [currentLanguage, setCurrentLanguage] = useState<Language | null>(null);
    const [loading, setLoading] = useState(true);

    const fetchLanguages = async () => {
        try {
            const res = await apiCall.invoke({ url: '/api/v1/languages', method: 'GET' });
            const data = res.data;
            setLanguages(data.items || []);

            const storedCode = localStorage.getItem('app_lang');
            let selected = null;
            if (data.items && data.items.length > 0) {
                if (storedCode) {
                    selected = data.items.find((l: Language) => l.code === storedCode);
                }
                if (!selected) {
                    selected = data.items.find((l: Language) => l.isDefault) || data.items[0];
                }
            }
            setCurrentLanguage(selected);
        } catch (e) {
            console.error('Failed to fetch languages:', e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLanguages();
    }, []);

    useEffect(() => {
        if (currentLanguage) {
            document.documentElement.dir = currentLanguage.isRtl ? 'rtl' : 'ltr';
            document.documentElement.lang = currentLanguage.code;
            localStorage.setItem('app_lang', currentLanguage.code);
        } else {
            document.documentElement.dir = 'rtl';
            document.documentElement.lang = 'ar';
        }
    }, [currentLanguage]);

    const setLanguage = useCallback((code: string) => {
        const lang = languages.find(l => l.code === code);
        if (lang) {
            setCurrentLanguage(lang);
        }
    }, [languages]);

    const t = useCallback((key: string, defaultValue?: string) => {
        if (!currentLanguage) {
            const staticItem = STATIC_LABELS_MAP.get(key);
            return staticItem ? staticItem.defaultAr : (defaultValue || key);
        }
        if (currentLanguage.translations && currentLanguage.translations[key]) {
            return currentLanguage.translations[key];
        }

        const staticItem = STATIC_LABELS_MAP.get(key);
        if (staticItem) {
            return currentLanguage.code === 'en' ? staticItem.defaultEn : staticItem.defaultAr;
        }

        return defaultValue || key;
    }, [currentLanguage]);

    const refreshLanguages = useCallback(async () => {
        await fetchLanguages();
    }, []);

    const isRTL = currentLanguage ? currentLanguage.isRtl : true;

    const contextValue = useMemo(() => ({
        languages,
        currentLanguage,
        setLanguage,
        t,
        loading,
        refreshLanguages,
        isRTL,
    }), [languages, currentLanguage, setLanguage, t, loading, refreshLanguages, isRTL]);

    return (
        <LanguageContext.Provider value={contextValue}>
            {children}
        </LanguageContext.Provider>
    );
};

    export const useLanguage = () => {
        const context = useContext(LanguageContext);
        if (context === undefined) {
            throw new Error('useLanguage must be used within a LanguageProvider');
        }
        return context;
    };
